    class Solution:
        def numSub(self, s: str) -> int:
            MOD = 10**9 + 7
            total = 0
            current = 0
            for c in s:
                if c == '1':
                    current += 1
                else:
                    if current > 0:
                        total += current * (current + 1) // 2
                        current = 0
            if current > 0:
                total += current * (current + 1) // 2
            return total % MOD

